I now have all the information I need. Let me compile the complete implementation plan.

---

## Implementation Plan: Stepper Compound Component

### Architectural Overview

The Stepper is a pure React compound component (no external dependencies like radix-ui) using a two-tier React context: a root `StepperContext` shared across all descendants, and a per-item `StepperItemContext` that gives child components like `StepperTrigger` and `StepperSeparator` access to their own step number and computed state. All state-based styling is driven by `data-[state=...]` Tailwind selectors rather than JS conditional class logic.

---

### 1. `stepper.tsx` — Complete Implementation

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775325276868-lx2jyy/apps/v4/registry/new-york-v4/ui/stepper.tsx`

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Context Types ──────────────────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

// ─── Contexts ───────────────────────────────────────────────────────────────

const StepperContext = React.createContext<StepperContextValue | null>(null)

const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

// ─── Hooks ──────────────────────────────────────────────────────────────────

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper (Root) ─────────────────────────────────────────────────────────

type StepperProps = {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps & React.ComponentProps<"div">) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start gap-2"
            : "flex-col items-start gap-2",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: StepperItemProps & React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()

  const state: "completed" | "active" | "pending" =
    activeStep > step
      ? "completed"
      : activeStep === step
        ? "active"
        : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        data-orientation={orientation}
        className={cn(
          "group flex items-center gap-2",
          orientation === "vertical" && "flex-col",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-full size-8 text-sm font-medium transition-colors outline-none",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50 focus-visible:border-ring",
        "disabled:pointer-events-none disabled:opacity-50",
        // pending
        "border-2 border-muted-foreground/30 text-muted-foreground",
        // active
        "data-[state=active]:border-primary data-[state=active]:text-primary",
        // completed
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ?? <span>{step + 1}</span>}
    </button>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────
//
// Sits inside StepperItem for step N. It is "completed" when activeStep > step,
// i.e. the user has moved past this step (meaning step N+1 is now at least active).

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()
  const { step } = useStepperItem()

  const separatorState = activeStep > step ? "completed" : "pending"

  return (
    <div
      data-slot="stepper-separator"
      data-state={separatorState}
      data-orientation={orientation}
      className={cn(
        "shrink-0 rounded-full bg-muted-foreground/30 transition-colors",
        "data-[state=completed]:bg-primary",
        // horizontal: thin horizontal bar that fills remaining space
        orientation === "horizontal" ? "h-0.5 flex-1" : "w-0.5 flex-1 min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ──────────────────────────────────────────────────────────

type StepperContentProps = {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps & React.ComponentProps<"div">) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

**Key design decisions:**

- `step` is 0-indexed throughout. `StepperTrigger` displays `step + 1` as the human-readable number.
- `StepperSeparator` computes `separatorState` by reading both `StepperContext` (for `activeStep`) and `StepperItemContext` (for `step`). The separator is "completed" when `activeStep > step`.
- `StepperItem` passes `data-orientation` down so separators and items can both respond to orientation without needing to re-read context in every child (though they can).
- The `group` class on `StepperItem` enables future use of `group-data-[...]` parent selectors if consumers want to style children based on the item state from CSS alone.
- `StepperContent` renders `null` when the step is not active — clean conditional render, no hidden `display:none` DOM clutter.
- No external dependencies beyond React and `cn()` — registry entry needs no `dependencies` array.

---

### 2. `stepper-demo.tsx` — Complete Implementation

**File:** `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775325276868-lx2jyy/apps/v4/registry/new-york-v4/examples/stepper-demo.tsx`

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  {
    title: "Account",
    description: "Create your account",
  },
  {
    title: "Profile",
    description: "Set up your profile",
  },
  {
    title: "Complete",
    description: "You're all set",
  },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  function handleNext() {
    setActiveStep((prev) => Math.min(prev + 1, steps.length - 1))
  }

  function handlePrevious() {
    setActiveStep((prev) => Math.max(prev - 1, 0))
  }

  return (
    <div className="flex w-full max-w-xl flex-col gap-8">
      <Stepper activeStep={activeStep}>
        {steps.map((step, index) => (
          <React.Fragment key={index}>
            <StepperItem step={index} className="flex-col items-center">
              <div className="flex items-center gap-2">
                <StepperTrigger onClick={() => setActiveStep(index)} />
              </div>
              <div className="flex flex-col items-center text-center">
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </div>
            </StepperItem>
            {index < steps.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>

      {steps.map((step, index) => (
        <StepperContent key={index} step={index}>
          <div className="rounded-lg border p-6 text-center">
            <p className="text-muted-foreground text-sm">
              {step.description} — step {index + 1} of {steps.length}
            </p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={handlePrevious}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={handleNext}
          disabled={activeStep === steps.length - 1}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

**Demo design notes:**

- Uses `React.Fragment` with key to interleave `StepperSeparator` between items without an extra wrapper div.
- The `StepperSeparator` is placed between items at the demo level (outside `StepperItem`). This means the separator cannot read `StepperItemContext`.

**Critical re-evaluation of separator placement:**

The requirements state the separator is placed inside `StepperItem`. Re-reading: "StepperSeparator sits between StepperItem(step=1) and StepperItem(step=2)". If the separator is a sibling to `StepperItem` rather than a child, the `StepperItemContext` approach breaks.

There are two valid architectural approaches:

**Option A (Separator as child of StepperItem — matches requirements exactly):**
The separator lives inside `StepperItem`, which means the JSX structure is:
```tsx
<StepperItem step={0}>
  <StepperTrigger />
  <StepperSeparator />  {/* reads step=0 from StepperItemContext, shows completed when activeStep > 0 */}
</StepperItem>
<StepperItem step={1}>
  <StepperTrigger />
  <StepperSeparator />  {/* last item gets no separator */}
</StepperItem>
```

**Option B (Separator as sibling — reads step prop directly):**
Give `StepperSeparator` its own `step` prop and drop the `StepperItemContext` dependency for it.

Option A matches the stated requirements ("StepperSeparator renders inside a StepperItem"). Here is the corrected demo using Option A, which is the canonical pattern:

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { title: "Account", description: "Create your account" },
  { title: "Profile", description: "Set up your profile" },
  { title: "Complete", description: "You're all set" },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8 p-4">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map((step, index) => (
          <React.Fragment key={index}>
            <StepperItem step={index} className="flex-1 flex-col gap-1 items-center">
              <StepperTrigger onClick={() => setActiveStep(index)} />
              <StepperTitle>{step.title}</StepperTitle>
            </StepperItem>
            {index < steps.length - 1 && (
              <StepperItem step={index} className="flex-1">
                <StepperSeparator />
              </StepperItem>
            )}
          </React.Fragment>
        ))}
      </Stepper>

      {steps.map((step, index) => (
        <StepperContent key={index} step={index}>
          <div className="rounded-lg border p-6">
            <p className="font-medium">{step.title}</p>
            <p className="text-muted-foreground mt-1 text-sm">{step.description}</p>
          </div>
        </StepperContent>
      ))}

      <div className="flex gap-2">
        <Button
          variant="outline"
          onClick={() => setActiveStep((p) => Math.max(0, p - 1))}
          disabled={activeStep === 0}
        >
          Previous
        </Button>
        <Button
          onClick={() => setActiveStep((p) => Math.min(steps.length - 1, p + 1))}
          disabled={activeStep === steps.length - 1}
        >
          Next
        </Button>
      </div>
    </div>
  )
}
```

Actually, the cleanest demo is one where the separator is a direct child of `StepperItem`, which is the intended pattern per the requirements. Here is the final clean version that matches the architecture:

```tsx
"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const steps = [
  { title: "Account", description: "Create your account" },
  { title: "Profile", description: "Set up your profile" },
  { title: "Complete", description: "You're all set" },
]

export default function StepperDemo() {
  const [activeStep, setActiveStep] = React.useState(0)

  return (
    <div className="flex w-full max-w-2xl flex-col gap-8 p-4">
      <Stepper activeStep={activeStep} className="w-full">
        {steps.map((step, index) => (
          <React.Fragment key={index}>
            <StepperItem step={index} className="flex-col items-center gap-1">
              <StepperTrigger onClick={() => setActiveStep(index)} />
