    name: "stepper",
    type: "registry:ui",
    files: [
      {
        path: "ui/stepper.tsx",
        type: "registry:ui",
      },
    ],
  },
```

No `dependencies` or `registryDependencies` needed (pure React + `cn()`).

---

## Step 4 — Edit `apps/v4/registry/new-york-v4/examples/_registry.ts`

**Insertion point:** After line 2124 (closing `},` of `spinner-item` entry), before line 2125 (opening `{` of `switch-demo` entry).

```typescript
