## Context

The project needs a new `Stepper` compound component — a multi-step progress indicator for wizards, onboarding flows, and checkout processes. The component must follow all shadcn/ui v4 conventions established by `carousel.tsx` (React context pattern), `tabs.tsx` (CVA + data-attribute selectors), and `accordion.tsx` (clean prop spreading). No existing files are modified; only 2 new files are created and 2 registry files get new entries appended in alphabetical position.

---

## Files to Create / Modify

| Action | File |
|--------|------|
| **Create** | `apps/v4/registry/new-york-v4/ui/stepper.tsx` |
| **Create** | `apps/v4/registry/new-york-v4/examples/stepper-demo.tsx` |
| **Edit** | `apps/v4/registry/new-york-v4/ui/_registry.ts` (insert between lines 563–564) |
| **Edit** | `apps/v4/registry/new-york-v4/examples/_registry.ts` (insert between lines 2124–2125) |

---

## Step 1 — Create `apps/v4/registry/new-york-v4/ui/stepper.tsx`

### Architecture

Two React contexts enable the compound component tree:

- **`StepperContext`** — shared by all descendants; holds `{ activeStep, orientation }`
- **`StepperItemContext`** — provided by each `StepperItem`; holds `{ step, state }`

Two internal hooks enforce correct usage with error-throwing guards:

```typescript
function useStepper() { /* throws if outside <Stepper /> */ }
function useStepperItem() { /* throws if outside <StepperItem /> */ }
```

### Complete file content

```tsx
"use client"

import * as React from "react"

import { cn } from "@/lib/utils"

// ─── Context ─────────────────────────────────────────────────────────────────

type StepperContextValue = {
  activeStep: number
  orientation: "horizontal" | "vertical"
}

type StepperItemContextValue = {
  step: number
  state: "completed" | "active" | "pending"
}

const StepperContext = React.createContext<StepperContextValue | null>(null)
const StepperItemContext = React.createContext<StepperItemContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper (Root) ──────────────────────────────────────────────────────────

type StepperProps = {
  activeStep: number
  orientation?: "horizontal" | "vertical"
}

function Stepper({
  activeStep,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps & React.ComponentProps<"div">) {
  return (
    <StepperContext.Provider value={{ activeStep, orientation }}>
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn(
          "flex",
          orientation === "horizontal"
            ? "flex-row items-start"
            : "flex-col items-start",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── StepperItem ─────────────────────────────────────────────────────────────

type StepperItemProps = {
  step: number
}

function StepperItem({
  step,
  className,
  children,
  ...props
}: StepperItemProps & React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()

  const state: "completed" | "active" | "pending" =
    activeStep > step ? "completed" : activeStep === step ? "active" : "pending"

  return (
    <StepperItemContext.Provider value={{ step, state }}>
      <div
        data-slot="stepper-item"
        data-step={step}
        data-state={state}
        data-orientation={orientation}
        className={cn("group flex items-center gap-2", className)}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { step, state } = useStepperItem()

  return (
    <button
      data-slot="stepper-trigger"
      data-state={state}
      className={cn(
        "inline-flex shrink-0 items-center justify-center rounded-full size-8 text-sm font-medium transition-colors outline-none",
        "focus-visible:ring-[3px] focus-visible:ring-ring/50",
        "disabled:pointer-events-none disabled:opacity-50",
        "border-2 border-muted-foreground/30 text-muted-foreground",
        "data-[state=active]:border-primary data-[state=active]:text-primary",
        "data-[state=completed]:border-primary data-[state=completed]:bg-primary data-[state=completed]:text-primary-foreground",
        className
      )}
      {...props}
    >
      {children ?? <span>{step + 1}</span>}
    </button>
  )
}

// ─── StepperTitle ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-title"
      className={cn("text-sm font-medium", className)}
      {...props}
    />
  )
}

// ─── StepperDescription ──────────────────────────────────────────────────────

function StepperDescription({ className, ...props }: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-sm text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ────────────────────────────────────────────────────────
//
// Reads StepperItemContext for step and StepperContext for orientation/activeStep.
// Shows as "completed" when activeStep > step (the user has moved past this step).

function StepperSeparator({ className, ...props }: React.ComponentProps<"div">) {
  const { activeStep, orientation } = useStepper()
  const { step } = useStepperItem()

  const separatorState = activeStep > step ? "completed" : "pending"

  return (
    <div
      data-slot="stepper-separator"
      data-state={separatorState}
      data-orientation={orientation}
      className={cn(
        "shrink-0 rounded-full bg-muted-foreground/30 transition-colors",
        "data-[state=completed]:bg-primary",
        orientation === "horizontal" ? "h-0.5 flex-1" : "w-0.5 flex-1 min-h-8",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ──────────────────────────────────────────────────────────

type StepperContentProps = {
  step: number
}

function StepperContent({
  step,
  className,
  children,
  ...props
}: StepperContentProps & React.ComponentProps<"div">) {
  const { activeStep } = useStepper()

  if (step !== activeStep) return null

  return (
    <div
      data-slot="stepper-content"
      data-step={step}
      className={cn("mt-4", className)}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ─────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}
```

### Key design decisions

- **0-indexed `step` prop** — programmatic; `StepperTrigger` displays `step + 1` as the human-visible number
- **`StepperSeparator` state logic** — "completed" when `activeStep > step` (user has moved past the current StepperItem), which is the standard visual convention (line fills as steps are passed)
- **No external npm deps** — only React + `cn()`, so no `dependencies` field in registry
- **`data-[state=...]` Tailwind selectors** — all state-driven styling is CSS-selector-based (not JS conditionals), matching tabs.tsx pattern
- **`StepperContent` returns `null`** — clean conditional render, no hidden DOM nodes

---

